import { readFileSync, existsSync } from 'node:fs';

/**
 * Shared Result Schema Validator
 * Validates machine-readable result JSON files generated by pipeline jobs.
 */
export function validateResultFile(filePath, expectedTest, expectedSha, expectedRunId) {
  if (!expectedSha || typeof expectedSha !== 'string' || expectedSha.trim() === '') {
    console.error('❌ FAIL CLOSED CONFIGURATION ERROR: expectedSha parameter is mandatory for result validation.');
    process.exit(1);
  }

  if (!expectedRunId || typeof expectedRunId !== 'string' || String(expectedRunId).trim() === '') {
    console.error('❌ FAIL CLOSED CONFIGURATION ERROR: expectedRunId parameter is mandatory for result validation.');
    process.exit(1);
  }

  if (!existsSync(filePath)) {
    console.error(`❌ FAIL CLOSED: Result file missing: ${filePath}`);
    process.exit(1);
  }

  let data;
  try {
    data = JSON.parse(readFileSync(filePath, 'utf8'));
  } catch (err) {
    console.error(`❌ FAIL CLOSED: Invalid JSON in ${filePath}:`, err.message);
    process.exit(1);
  }

  // 1. Mandatory Top-Level Schema Fields
  const requiredFields = ['test', 'status', 'commit_sha', 'workflow_run_id', 'timestamp', 'details'];
  for (const f of requiredFields) {
    if (!data[f] || typeof data[f] !== 'string' || data[f].trim() === '') {
      console.error(`❌ FAIL CLOSED: Missing required top-level field "${f}" in ${filePath}`);
      process.exit(1);
    }
  }

  // 2. Test Name Check
  if (data.test !== expectedTest) {
    console.error(`❌ FAIL CLOSED: Test name mismatch in ${filePath}. Expected "${expectedTest}", got "${data.test}"`);
    process.exit(1);
  }

  // 3. Status Check
  if (data.status !== 'STAGING PASS') {
    console.error(`❌ FAIL CLOSED: Invalid status in ${filePath}. Expected "STAGING PASS", got "${data.status}"`);
    process.exit(1);
  }

  // 4. Provenance Commit SHA & Workflow Run ID Match
  if (data.commit_sha !== expectedSha) {
    console.error(`❌ FAIL CLOSED PROVENANCE VIOLATION: Commit SHA mismatch in ${filePath}. Expected "${expectedSha}", got "${data.commit_sha}"`);
    process.exit(1);
  }

  if (String(data.workflow_run_id) !== String(expectedRunId)) {
    console.error(`❌ FAIL CLOSED PROVENANCE VIOLATION: Workflow Run ID mismatch in ${filePath}. Expected "${expectedRunId}", got "${data.workflow_run_id}"`);
    process.exit(1);
  }

  // 5. Timestamp Rules: Valid ISO, Fresh (< 24h), Not in Future (> 5 min skew)
  const tsTime = new Date(data.timestamp).getTime();
  if (isNaN(tsTime)) {
    console.error(`❌ FAIL CLOSED: Malformed timestamp "${data.timestamp}" in ${filePath}`);
    process.exit(1);
  }

  const now = Date.now();
  if (tsTime > now + 5 * 60 * 1000) {
    console.error(`❌ FAIL CLOSED: Timestamp in ${filePath} is in the future beyond clock skew allowance (${data.timestamp})`);
    process.exit(1);
  }

  if (now - tsTime > 24 * 3600 * 1000) {
    console.error(`❌ FAIL CLOSED: Timestamp in ${filePath} is expired (> 24 hours old)`);
    process.exit(1);
  }

  // 6. Complete Test-Specific Schema Verification
  function assertField(field, type = 'string') {
    if (data[field] === undefined || data[field] === null) {
      console.error(`❌ FAIL CLOSED: Missing test-specific field "${field}" in ${filePath}`);
      process.exit(1);
    }
    if (typeof data[field] !== type) {
      console.error(`❌ FAIL CLOSED: Field "${field}" in ${filePath} must be type ${type}, got ${typeof data[field]}`);
      process.exit(1);
    }
  }

  if (expectedTest === 'staging-database') {
    ['migration_status', 'rpc_resolution_status', 'cash_status', 'visa_status', 'mixed_status', 'rls_status', 'rollback_status', 'staging_database_host'].forEach(f => assertField(f, 'string'));
  } else if (expectedTest === 'playwright') {
    ['staging_url', 'cash_status', 'visa_status', 'mixed_status', 'currency_status', 'validation_status', 'sorting_status', 'analytics_status', 'rls_status'].forEach(f => assertField(f, 'string'));
    assertField('passed_tests', 'number');
    assertField('failed_tests', 'number');
  } else if (expectedTest === 'desktop-updater-metadata') {
    ['version', 'installer_filename', 'blockmap_filename', 'latest_yml_filename', 'latest_yml_sha512'].forEach(f => assertField(f, 'string'));
    assertField('installer_exists', 'boolean');
    assertField('blockmap_exists', 'boolean');
  } else if (expectedTest === 'desktop-upgrade') {
    ['previous_version', 'candidate_version', 'installed_previous_version', 'detected_candidate_version', 'downloaded_asset_sha256', 'relaunched_version', 'save_trip_result', 'edit_trip_result', 'test_machine_id', 'evidence_session_id', 'sanitized_updater_log'].forEach(f => assertField(f, 'string'));
    assertField('installer_process_exit_code', 'number');
  } else if (expectedTest === 'artifact-integrity') {
    ['installer_filename', 'installer_sha256', 'blockmap_filename', 'blockmap_sha256', 'latest_yml_filename', 'latest_yml_sha256', 'latest_yml_version', 'latest_yml_installer_filename', 'latest_yml_sha512'].forEach(f => assertField(f, 'string'));
    assertField('installer_size', 'number');
    assertField('blockmap_size', 'number');
    assertField('latest_yml_size', 'number');
  }

  console.log(`✓ Complete schema validation passed for ${filePath} (${expectedTest})`);
  return true;
}

// CLI Execution Mode when called directly from command line
if (process.argv[1] && process.argv[1].endsWith('validate-result-schema.mjs')) {
  const file = process.argv[2];
  const expectedTest = process.argv[3];
  const expectedSha = process.env.COMMIT_SHA || process.env.GITHUB_SHA;
  const expectedRunId = process.env.RUN_ID || process.env.GITHUB_RUN_ID;

  if (!file || !expectedTest) {
    console.error('Usage: node scripts/validate-result-schema.mjs <file> <expectedTest>');
    process.exit(1);
  }

  validateResultFile(file, expectedTest, expectedSha, expectedRunId);
}
